const ToolIcon = ({ tool }: { tool: AITool }) => {
  const [error, setError] = useState(false);
  const [isHovered, setIsHovered] = useState(false);

  const handleClick = () => {
    window.open(`https://api.supioc.com/pricing?provider=${encodeURIComponent(tool.name)}`, '_blank');
  };

  return (
    <div className="relative flex flex-col items-center">
      <motion.div
        whileHover={{ scale: 1.1, y: -5 }}
        transition={{ type: 'spring', stiffness: 400, damping: 17 }}
        onMouseEnter={() => setIsHovered(true)}
        onMouseLeave={() => setIsHovered(false)}
        onClick={handleClick}
        className="w-20 h-20 rounded-2xl bg-white dark:bg-zinc-800 shadow-sm border border-zinc-200 dark:border-zinc-700 flex items-center justify-center overflow-hidden cursor-pointer apple-watch-hover group"
      >
        {tool.logoUrl && !error ? (
          <img 
            src={tool.logoUrl} 
            alt={tool.name} 
            className="w-12 h-12 object-contain" 
            onError={() => setError(true)}
            referrerPolicy="no-referrer"
          />
        ) : (
          <div className={`w-full h-full ${tool.color} flex items-center justify-center text-white`}>
            <tool.icon size={32} />
          </div>
        )}
        <div className="absolute inset-0 bg-black/5 opacity-0 group-hover:opacity-100 transition-opacity" />
      </motion.div>
      
      <AnimatePresence>
        {isHovered && (
          <motion.div
            initial={{ opacity: 0, y: 10, scale: 0.95 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 10, scale: 0.95 }}
            className="absolute bottom-full mb-3 px-3 py-1.5 bg-zinc-900 dark:bg-white text-white dark:text-zinc-900 text-xs font-bold rounded-lg shadow-xl whitespace-nowrap z-50 pointer-events-none"
          >
            {tool.name}
            <div className="absolute -bottom-1 left-1/2 -translate-x-1/2 w-2 h-2 bg-zinc-900 dark:bg-white rotate-45" />
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

const ToolRow = ({ tools, direction = 'left' }: { tools: AITool[], direction?: 'left' | 'right' }) => {
  return (
    <div className="flex py-4">
      <motion.div
        animate={{
          x: direction === 'left' ? ["0%", "-50%"] : ["-50%", "0%"],
        }}
        transition={{
          duration: 100,
          repeat: Infinity,
          ease: "linear",
        }}
        className="flex w-max"
      >
        <div className="flex gap-6 pr-6">
          {tools.map((tool, idx) => (
            <div key={`set1-${tool.id}-${idx}`}>
              <ToolIcon tool={tool} />
            </div>
          ))}
        </div>
        <div className="flex gap-6 pr-6">
          {tools.map((tool, idx) => (
            <div key={`set2-${tool.id}-${idx}`}>
              <ToolIcon tool={tool} />
            </div>
          ))}
        </div>
      </motion.div>
    </div>
  );
};

export const Home: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [isSearchFocused, setIsSearchFocused] = useState(false);

  const filteredTools = useMemo(() => {
    if (!searchQuery) return [];
    return AI_TOOLS.filter(tool => 
      tool.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      tool.category.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [searchQuery]);

  const shuffledTools = useMemo(() => [...AI_TOOLS].sort(() => Math.random() - 0.5), []);
  const row1 = shuffledTools;
  const row2 = useMemo(() => {
    const half = Math.floor(shuffledTools.length / 2);
    return [...shuffledTools.slice(half), ...shuffledTools.slice(0, half)];
  }, [shuffledTools]);

  return (
    <div className="h-full w-full flex flex-col items-center justify-center px-6 py-12 bg-zinc-50 dark:bg-zinc-950">
      <div className="w-full max-w-4xl flex flex-col items-center">
        {/* Centered Logo */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="mb-8"
        >
          <div className="w-20 h-20 rounded-2xl bg-zinc-900 dark:bg-white flex items-center justify-center text-white dark:text-zinc-900 font-bold text-4xl shadow-sm">
            S
          </div>
        </motion.div>

        {/* Intro Text */}
        <div className="text-center mb-10">
          <h1 className="text-5xl font-bold tracking-tight dark:text-white mb-4">
            Supioc AI Explorer
          </h1>
          <p className="text-lg text-zinc-500 dark:text-zinc-400 max-w-xl mx-auto font-medium">
            探索全球最顶尖的 AI 工具。简洁、高效、触手可及。
          </p>
        </div>

        {/* Search Bar */}
        <div className="w-full max-w-2xl relative mb-16">
          <div className="relative">
            <div className="absolute left-5 top-1/2 -translate-y-1/2 text-zinc-400">
              <Search size={20} />
            </div>
            <input
              type="text"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              onFocus={() => setIsSearchFocused(true)}
              onBlur={() => setTimeout(() => setIsSearchFocused(false), 200)}
              placeholder="搜索 AI 工具..."
              className="w-full py-4 pl-14 pr-6 rounded-2xl bg-white dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-800 dark:text-white outline-none text-lg shadow-sm focus:ring-2 focus:ring-zinc-200 dark:focus:ring-zinc-800 transition-all"
            />
            
            {/* Search Results */}
            <AnimatePresence>
              {isSearchFocused && filteredTools.length > 0 && (
                <motion.div
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, y: 10 }}
                  className="absolute top-full left-0 right-0 mt-3 p-2 bg-white dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-800 rounded-2xl z-50 shadow-xl max-h-80 overflow-y-auto"
                >
                  {filteredTools.map(tool => (
                    <div key={tool.id} className="flex items-center gap-3 p-3 rounded-xl hover:bg-zinc-50 dark:hover:bg-zinc-800 transition-colors cursor-pointer group">
                      <div className="w-10 h-10 rounded-lg overflow-hidden border border-zinc-100 dark:border-zinc-800 flex items-center justify-center bg-white">
                        {tool.logoUrl ? (
                          <img src={tool.logoUrl} alt="" className="w-6 h-6 object-contain" referrerPolicy="no-referrer" />
                        ) : (
                          <tool.icon size={20} className="text-zinc-400" />
                        )}
                      </div>
                      <div className="flex-1">
                        <h4 className="font-semibold dark:text-white text-sm">{tool.name}</h4>
                        <span className="text-[10px] font-bold uppercase tracking-wider text-zinc-400">{tool.category}</span>
                      </div>
                      <ArrowRight size={14} className="text-zinc-300 opacity-0 group-hover:opacity-100 transition-opacity" />
                    </div>
                  ))}
                </motion.div>
              )}
            </AnimatePresence>
          </div>
        </div>

        {/* Scrolling Rows */}
        <div className="w-screen overflow-hidden opacity-80 pt-12 -mt-12">
          <ToolRow tools={row1} direction="left" />
          <ToolRow tools={row2} direction="right" />
        </div>
      </div>
    </div>
  );
};
